import boto3
import json
import uuid
from datetime import datetime
from typing import Dict, Any, Optional, List


class SQSPublisher:
    def __init__(self, queue_url: str, region_name: str = 'us-east-1'):
        self.queue_url = queue_url
        self.sqs_client = boto3.client('sqs', region_name=region_name)
    
    def publish_user_data(self, user_data: Dict[str, Any], message_group_id: Optional[str] = None) -> Dict[str, Any]:
        message_body = {
            'message_id': str(uuid.uuid4()),
            'timestamp': datetime.utcnow().isoformat(),
            'user_data': user_data
        }
        
        message_attributes = {
            'MessageType': {
                'StringValue': 'UserData',
                'DataType': 'String'
            },
            'ContainsPII': {
                'StringValue': 'true',
                'DataType': 'String'
            }
        }
        
        params = {
            'QueueUrl': self.queue_url,
            'MessageBody': json.dumps(message_body),
            'MessageAttributes': message_attributes
        }
        
        if message_group_id:
            params['MessageGroupId'] = message_group_id
            params['MessageDeduplicationId'] = str(uuid.uuid4())
        
        response = self.sqs_client.send_message(**params)
        
        return {
            'message_id': response['MessageId'],
            'sequence_number': response.get('SequenceNumber'),
            'status': 'published'
        }
    
    def publish_batch(self, user_data_list: List[Dict[str, Any]], message_group_id: Optional[str] = None) -> Dict[str, Any]:
        entries = []
        
        for idx, user_data in enumerate(user_data_list):
            message_body = {
                'message_id': str(uuid.uuid4()),
                'timestamp': datetime.utcnow().isoformat(),
                'user_data': user_data
            }
            
            entry = {
                'Id': str(idx),
                'MessageBody': json.dumps(message_body),
                'MessageAttributes': {
                    'MessageType': {
                        'StringValue': 'UserData',
                        'DataType': 'String'
                    },
                    'ContainsPII': {
                        'StringValue': 'true',
                        'DataType': 'String'
                    }
                }
            }
            
            if message_group_id:
                entry['MessageGroupId'] = message_group_id
                entry['MessageDeduplicationId'] = str(uuid.uuid4())
            
            entries.append(entry)
        
        response = self.sqs_client.send_message_batch(
            QueueUrl=self.queue_url,
            Entries=entries
        )
        
        return {
            'successful': len(response.get('Successful', [])),
            'failed': len(response.get('Failed', [])),
            'successful_messages': response.get('Successful', []),
            'failed_messages': response.get('Failed', [])
        }
    
    def publish_user_profile(self, user_id: str, email: str, phone_number: str, 
                            address: Dict[str, str], additional_data: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
        user_data = {
            'user_id': user_id,
            'email': email,
            'phone_number': phone_number,
            'address': address
        }
        
        if additional_data:
            user_data.update(additional_data)
        
        return self.publish_user_data(user_data)
    
    def publish_registration(self, email: str, phone_number: str, first_name: str, 
                            last_name: str, address: Dict[str, str]) -> Dict[str, Any]:
        user_data = {
            'event_type': 'user_registration',
            'email': email,
            'phone_number': phone_number,
            'first_name': first_name,
            'last_name': last_name,
            'address': address,
            'registration_date': datetime.utcnow().isoformat()
        }
        
        return self.publish_user_data(user_data)
    
    def publish_update(self, user_id: str, updated_fields: Dict[str, Any]) -> Dict[str, Any]:
        user_data = {
            'event_type': 'user_update',
            'user_id': user_id,
            'updated_fields': updated_fields,
            'update_timestamp': datetime.utcnow().isoformat()
        }
        
        return self.publish_user_data(user_data)
    
    def publish_contact_info(self, user_id: str, email: Optional[str] = None, 
                            phone_number: Optional[str] = None, 
                            alternate_email: Optional[str] = None) -> Dict[str, Any]:
        contact_data = {
            'user_id': user_id,
            'event_type': 'contact_info_update'
        }
        
        if email:
            contact_data['email'] = email
        if phone_number:
            contact_data['phone_number'] = phone_number
        if alternate_email:
            contact_data['alternate_email'] = alternate_email
        
        return self.publish_user_data(contact_data)
    
    def publish_address_change(self, user_id: str, new_address: Dict[str, str], 
                              old_address: Optional[Dict[str, str]] = None) -> Dict[str, Any]:
        address_data = {
            'user_id': user_id,
            'event_type': 'address_change',
            'new_address': new_address
        }
        
        if old_address:
            address_data['old_address'] = old_address
        
        return self.publish_user_data(address_data)


